     *   ->withID(...)
     *   ->withContainer(...)
     *   ->withContent(...)
     *   ->withModel(...)
     *   ->withStopDetails(...)
     *   ->withStopReason(...)
     *   ->withStopSequence(...)
     *   ->withUsage(...)
     * ```
     */
    public function __construct()
